-- AI PM LAB Resource Library: metadata only. Downloadable assets remain in public/downloads on Netlify.
create extension if not exists pgcrypto;
create or replace function public.set_updated_at() returns trigger language plpgsql security invoker as $$ begin new.updated_at=now(); return new; end $$;
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade,username text not null check (char_length(btrim(username)) between 2 and 40 and username=btrim(username)),email text not null check (email=btrim(lower(email))),membership_tier text not null default 'free' check (membership_tier in ('free','premium','client','admin')),marketing_consent boolean not null default false,privacy_accepted_at timestamptz not null,source text not null default 'resources',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),last_access_at timestamptz);
create table if not exists public.resources (id uuid primary key default gen_random_uuid(),slug text unique not null,title text not null,description text not null,category text not null,resource_type text not null default 'PDF',status text not null default 'coming_soon' check(status in('available','coming_soon','archived')),access_level text not null default 'free_member' check(access_level in('public','free_member','premium','client')),is_featured boolean not null default false,sort_order int not null default 0,published_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.resource_files (id uuid primary key default gen_random_uuid(),resource_id uuid not null references public.resources(id) on delete cascade,language_code text not null check(language_code in('en','it','other')),language_label text not null,file_name text not null,public_url text not null,mime_type text not null default 'application/pdf',file_format text not null default 'pdf',sort_order int not null default 0,created_at timestamptz not null default now(),unique(resource_id,language_code,file_name));
create table if not exists public.resource_bookmarks (user_id uuid references auth.users(id) on delete cascade,resource_id uuid references public.resources(id) on delete cascade,created_at timestamptz not null default now(),primary key(user_id,resource_id));
create table if not exists public.resource_activity (id bigint generated by default as identity primary key,user_id uuid references auth.users(id) on delete cascade,resource_id uuid references public.resources(id) on delete cascade,resource_file_id uuid references public.resource_files(id) on delete set null,event_type text not null check(event_type in('view','open','download','save','unsave')),created_at timestamptz not null default now());
create table if not exists public.resource_access_grants (id uuid primary key default gen_random_uuid(),user_id uuid references auth.users(id) on delete cascade,resource_id uuid references public.resources(id) on delete cascade,access_type text not null check(access_type in('premium','purchase','client','promotional','admin')),source text,granted_at timestamptz not null default now(),expires_at timestamptz,created_at timestamptz not null default now());
create index if not exists resource_activity_user_idx on public.resource_activity(user_id);create index if not exists resource_activity_resource_idx on public.resource_activity(resource_id);create index if not exists resource_activity_created_idx on public.resource_activity(created_at desc);
drop trigger if exists profiles_updated_at on public.profiles;create trigger profiles_updated_at before update on public.profiles for each row execute function public.set_updated_at();drop trigger if exists resources_updated_at on public.resources;create trigger resources_updated_at before update on public.resources for each row execute function public.set_updated_at();
alter table public.profiles enable row level security;alter table public.resources enable row level security;alter table public.resource_files enable row level security;alter table public.resource_bookmarks enable row level security;alter table public.resource_activity enable row level security;alter table public.resource_access_grants enable row level security;
create policy "own profile select" on public.profiles for select to authenticated using(id=auth.uid());create policy "own profile insert" on public.profiles for insert to authenticated with check(id=auth.uid());create policy "own profile update" on public.profiles for update to authenticated using(id=auth.uid()) with check(id=auth.uid());
create policy "catalog preview" on public.resources for select to anon,authenticated using(status in('available','coming_soon') and access_level in('public','free_member'));create policy "public file links" on public.resource_files for select to anon using(exists(select 1 from public.resources r where r.id=resource_id and r.status='available' and r.access_level='public'));create policy "member file links" on public.resource_files for select to authenticated using(exists(select 1 from public.resources r where r.id=resource_id and r.status='available' and (r.access_level in('public','free_member') or exists(select 1 from public.resource_access_grants g where g.user_id=auth.uid() and g.resource_id=r.id and (g.expires_at is null or g.expires_at>now())))));
create policy "own bookmarks select" on public.resource_bookmarks for select to authenticated using(user_id=auth.uid());create policy "own bookmarks insert" on public.resource_bookmarks for insert to authenticated with check(user_id=auth.uid());create policy "own bookmarks delete" on public.resource_bookmarks for delete to authenticated using(user_id=auth.uid());create policy "own activity select" on public.resource_activity for select to authenticated using(user_id=auth.uid());create policy "own activity insert" on public.resource_activity for insert to authenticated with check(user_id=auth.uid());create policy "own grants select" on public.resource_access_grants for select to authenticated using(user_id=auth.uid());
-- Seeded from the existing Resources catalogue. Existing verified files change matching cards to available.
insert into public.resources(slug,title,description,category,resource_type,status,access_level,is_featured,sort_order) values
('before-you-prompt-clarity-checklist','Before You Prompt: The Clarity Checklist','Define the objective, audience, context, inputs, constraints, and format before writing a prompt.','AI & Prompting','Checklist','available','public',true,1),('one-prompt-framework','The One Prompt Framework You Actually Need','A reusable professional structure for almost any AI-assisted task.','AI & Prompting','Framework','available','public',true,2),('vague-request-to-professional-prompt','From Vague Request to Professional Prompt','Before-and-after examples that turn unclear requests into usable instructions.','AI & Prompting','Practical Guide','available','public',true,3),('professional-prompts-everyday-work','20 Professional Prompts for Everyday Work','Practical prompts for emails, documents, meetings, analysis, decisions, follow-ups, and planning.','AI & Prompting','Prompt Kit','available','free_member',false,4),('instructions-improve-ai-answer','25 Instructions That Improve Almost Any AI Answer','Use critique, comparison, checklists, red teaming, summaries, and decision matrices.','AI & Prompting','Cheat Sheet','available','free_member',false,5),('which-ai-tool-for-each-task','Which AI Tool Should You Use for Each Task?','Choose the right tool for writing, research, documents, data, images, code, and automation.','AI & Prompting','Tool Guide','available','free_member',false,6),('ai-email-toolkit','The AI Email Toolkit','Templates for professional requests, reminders, follow-ups, refusals, and sensitive messages.','Professional Communication','Email Toolkit','available','free_member',false,7),('write-like-a-human-with-ai','Write Like a Human with AI','Remove robotic language, generic phrases, unnecessary formality, and artificial tone.','Professional Communication','Writing Guide','available','free_member',false,8),('difficult-conversation-prompt-kit','The Difficult Conversation Prompt Kit','Prepare feedback, address delays, clarify responsibilities, and manage conflict.','Professional Communication','Prompt Kit','coming_soon','free_member',false,9),('client-follow-up-prompt-pack','Client Follow-Up Prompt Pack','Follow up after calls, proposals, events, presentations, and unanswered messages.','Professional Communication','Prompt Pack','available','free_member',false,10),('turn-notes-into-documents','Turn Notes into Clear Professional Documents','Convert unstructured notes into emails, briefs, reports, procedures, and action plans.','Professional Communication','Document Builder','coming_soon','free_member',false,11),('prompts-think-like-consultant','30 Prompts to Think Like a Consultant','Apply pre-mortems, Pareto analysis, MECE, opportunity cost, five whys, and process audits.','Decisions & Business','Prompt Library','coming_soon','free_member',false,12),('validate-business-idea-with-ai','Validate Your Business Idea with AI','Examine the problem, customer, market, competitors, costs, risks, and first practical test.','Decisions & Business','Validation Guide','coming_soon','free_member',false,13),('understand-customers-with-ai','Understand Your Customers with AI','Identify customer needs, language, objections, channels, and assumptions that require validation.','Decisions & Business','Customer Analysis','coming_soon','free_member',false,14),('ai-research-fact-checking-checklist','The AI Research and Fact-Checking Checklist','Separate facts, assumptions, inferences, credible sources, and unverified information.','Decisions & Business','Checklist','coming_soon','free_member',false,15),('stakeholder-analysis-ai-pm-demo','Stakeholder Analysis AI + PM Demo','Download the demo package with Word, Excel, and PowerPoint files for a stakeholder analysis workflow created with AI and project management structure.','Decisions & Business','Demo Package','coming_soon','free_member',false,16),('ai-meeting-system','The AI Meeting System','Prepare meetings, capture decisions, assign actions, and manage professional follow-up.','Productivity & Organization','Operating System','coming_soon','free_member',false,17),('ai-action-plan-builder','The AI Action Plan Builder','Turn an objective into milestones, tasks, owners, deadlines, and completion criteria.','Productivity & Organization','Action Planner','coming_soon','free_member',false,18),('personal-weekly-review-with-ai','The Personal Weekly Review with AI','Review progress, blockers, unfinished work, changing priorities, and next actions.','Productivity & Organization','Weekly Review','coming_soon','free_member',false,19) on conflict(slug) do update set status=excluded.status,access_level=excluded.access_level,sort_order=excluded.sort_order,updated_at=now();
insert into public.resource_files(resource_id,language_code,language_label,file_name,public_url,sort_order) select r.id,v.code,v.label,v.file_name,'/downloads/'||v.file_name,v.sort_order from (values
('before-you-prompt-clarity-checklist','en','English','before-you-prompt-clarity-checklist.pdf',1),('before-you-prompt-clarity-checklist','it','Italiano','before-you-prompt-clarity-checklist_ITA.pdf',2),('one-prompt-framework','en','English','The_One_Prompt_Framework_AI_PM_Lab.pdf',1),('one-prompt-framework','it','Italiano','The_One_Prompt_Framework_AI_PM_Lab_ITA.pdf',2),('vague-request-to-professional-prompt','en','English','From_Vague_Request_to_Professional_Prompt_AI_PM_Lab.pdf',1),('vague-request-to-professional-prompt','it','Italiano','From_Vague_Request_to_Professional_Prompt_AI_PM_Lab_ITA.pdf',2),('professional-prompts-everyday-work','en','English','20_Professional_Prompts_for_Everyday_Work_AI_PM_Lab.pdf',1),('professional-prompts-everyday-work','it','Italiano','20_Professional_Prompts_for_Everyday_Work_AI_PM_Lab_ITA.pdf',2),('instructions-improve-ai-answer','en','English','25_Instructions_That_Improve_Almost_Any_AI_Answer_AI_PM_Lab.pdf',1),('instructions-improve-ai-answer','it','Italiano','25_Instructions_That_Improve_Almost_Any_AI_Answer_AI_PM_Lab_ITA.pdf',2),('which-ai-tool-for-each-task','en','English','Which_AI_Tool_Should_You_Use_for_Each_Task_AI_PM_Lab.pdf',1),('ai-email-toolkit','en','English','The_AI_Email_Toolkit_AI_PM_Lab.pdf',1),('ai-email-toolkit','it','Italiano','The_AI_Email_Toolkit_AI_PM_Lab_ITA.pdf',2),('write-like-a-human-with-ai','en','English','Write_Like_a_Human_with_AI_AI_PM_Lab.pdf',1),('client-follow-up-prompt-pack','en','English','Client_Follow_Up_Prompt_Pack_AI_PM_Lab.pdf',1),('client-follow-up-prompt-pack','it','Italiano','Client_Follow_Up_Prompt_Pack_AI_PM_Lab_ITA.pdf',2)) as v(slug,code,label,file_name,sort_order) join public.resources r on r.slug=v.slug on conflict(resource_id,language_code,file_name) do update set public_url=excluded.public_url,sort_order=excluded.sort_order;
